import{_ as a,c as n,o as e,aN as l}from"./chunks/framework.BRm39z_l.js";const M=JSON.parse('{"title":"Mysql存储引擎","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/03. Mysql存储引擎.md","filePath":"mysql/03. Mysql存储引擎.md"}'),r={name:"mysql/03. Mysql存储引擎.md"};function i(t,o,f,p,s,d){return e(),n("div",null,o[0]||(o[0]=[l('<h1 id="mysql存储引擎" tabindex="-1">Mysql存储引擎 <a class="header-anchor" href="#mysql存储引擎" aria-label="Permalink to &quot;Mysql存储引擎&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#mysql-中有哪些常见的存储引擎">MySQL 中有哪些常见的存储引擎</a></li><li><a href="#存储引擎应该怎么选择">存储引擎应该怎么选择？</a></li><li><a href="#innodb-和-myisam-主要有什么区别">InnoDB 和 MyISAM 主要有什么区别？</a></li><li><a href="#innodb-的-buffer-pool-了解吗">InnoDB 的 Buffer Pool 了解吗</a></li><li><a href="#innodb-的内存结构">innodb 的内存结构</a></li></ul></nav><h2 id="mysql-中有哪些常见的存储引擎" tabindex="-1">MySQL 中有哪些常见的存储引擎 <a class="header-anchor" href="#mysql-中有哪些常见的存储引擎" aria-label="Permalink to &quot;MySQL 中有哪些常见的存储引擎&quot;">​</a></h2><p>MySQL 支持多种存储引擎，常见的有 MyISAM、InnoDB、MEMORY 等。</p><h2 id="存储引擎应该怎么选择" tabindex="-1">存储引擎应该怎么选择？ <a class="header-anchor" href="#存储引擎应该怎么选择" aria-label="Permalink to &quot;存储引擎应该怎么选择？&quot;">​</a></h2><p>大多数情况下，使用默认的 InnoDB 就可以了，InnoDB 可以提供事务、行级锁、外键、B+ 树索引等能力。</p><p>MyISAM 适合读多写少的场景</p><p>MEMORY 适合临时表，数据量不大的情况。因为数据都存放在内存，所以速度非常快。</p><h2 id="innodb-和-myisam-主要有什么区别" tabindex="-1">InnoDB 和 MyISAM 主要有什么区别？ <a class="header-anchor" href="#innodb-和-myisam-主要有什么区别" aria-label="Permalink to &quot;InnoDB 和 MyISAM 主要有什么区别？&quot;">​</a></h2><p>InnoDB 和 MyISAM 的最大区别在于事务支持和锁机制</p><p>InnoDB 支持事务、行级锁，适合大多数业务系统</p><p>而 MyISAM 不支持事务，用的是表锁，查询快但写入性能差，适合读多写少的场景</p><p>从存储结构上来说，MyISAM 用三种格式的文件来存储，.frm 文件存储表的定义；.MYD 存储数据；.MYI 存储索</p><p>InnoDB 用两种格式的文件来存储，.frm 文件存储表的定义；.ibd 存储数据和索引。</p><p>MyISAM 为非聚簇索引，索引和数据分开存储，索引保存的是数据文件的指针</p><p>InnoDB 为聚簇索引，索引和数据不分开</p><h2 id="innodb-的-buffer-pool-了解吗" tabindex="-1">InnoDB 的 Buffer Pool 了解吗 <a class="header-anchor" href="#innodb-的-buffer-pool-了解吗" aria-label="Permalink to &quot;InnoDB 的 Buffer Pool 了解吗&quot;">​</a></h2><p>Buffer Pool 是 InnoDB 存储引擎中的一个内存缓冲区，它会将经常使用的数据页、索引页加载进内存，读的时候先查询 Buffer Pool，如果命中就不用访问磁盘了。</p><p>如果没有命中，就从磁盘读取，并加载到 Buffer Pool，此时可能会触发页淘汰，将不常用的页移出 Buffer Pool</p><p>写操作时不会直接写入磁盘，而是先修改内存中的页，此时页被标记为脏页，后台线程会定期将脏页刷新到磁盘</p><p>Buffer Pool 可以显著减少磁盘的读写次数，从而提升 MySQL 的读写性能</p><h2 id="innodb-的内存结构" tabindex="-1">innodb 的内存结构 <a class="header-anchor" href="#innodb-的内存结构" aria-label="Permalink to &quot;innodb 的内存结构&quot;">​</a></h2><p>InnoDB 的内存区域主要有两块，buffer pool 和 log buffer</p><p>buffer pool 用于缓存数据页和索引页，提升读写性能</p><p>log buffer 用于缓存 redo log，提升写入性能。</p>',25)]))}const u=a(r,[["render",i]]);export{M as __pageData,u as default};
